CREATE PROCEDURE assoc.sp_Dashboard_GetHeldAdvanceMoney @TenantId INT, @AssociationId INT AS BEGIN SET NOCOUNT ON; SELECT CAST(ISNULL(SUM(Amount), 0) AS DECIMAL(18,2)) as TotalAdvanceCredits, COUNT(DISTINCT AssetId) as UnitsWithCredit FROM assoc.Payments WHERE TenantId = @TenantId AND AssociationId = @AssociationId AND InvoiceId IS NULL AND Status IN ('Paid', 'Completed'); END